// ABSTRACT PRODUCTS
interface Button   { void paint(); }
interface Checkbox { void paint(); }

// WINDOWS FAMILY
class WinButton   implements Button   { public void paint() { System.out.println("Windows Button"); } }
class WinCheckbox implements Checkbox { public void paint() { System.out.println("Windows Checkbox"); } }

// MACOS FAMILY
class MacButton   implements Button   { public void paint() { System.out.println("macOS Button"); } }
class MacCheckbox implements Checkbox { public void paint() { System.out.println("macOS Checkbox"); } }

// ABSTRACT FACTORY
interface GUIFactory {
    Button   createButton();
    Checkbox createCheckbox();
}

// CONCRETE FACTORIES
class WinFactory implements GUIFactory {
    public Button   createButton()   { return new WinButton(); }
    public Checkbox createCheckbox() { return new WinCheckbox(); }
}
class MacFactory implements GUIFactory {
    public Button   createButton()   { return new MacButton(); }
    public Checkbox createCheckbox() { return new MacCheckbox(); }
}

// CLIENT — never sees concrete class names
class Application {
    private Button button;
    private Checkbox checkbox;

    public Application(GUIFactory factory) {
        button   = factory.createButton();
        checkbox = factory.createCheckbox();
    }
    public void paint() { button.paint(); checkbox.paint(); }
}

// INITIALIZATION — the only impure place
public class Demo {
    public static void main(String[] args) {
        String os = System.getProperty("os.name").toLowerCase();
        GUIFactory factory = os.contains("mac") ? new MacFactory() : new WinFactory();
        new Application(factory).paint();
    }
}

// ABSTRACT PRODUCTS
interface ComputeInstance { void bootUp(); void shutDown(); }
interface CloudStorage    { void uploadData(String data); }

// AWS FAMILY
class EC2Instance implements ComputeInstance {
    public void bootUp()   { System.out.println("[AWS] Booting EC2..."); }
    public void shutDown() { System.out.println("[AWS] Stopping EC2."); }
}
class S3Storage implements CloudStorage {
    public void uploadData(String d) { System.out.println("[AWS] Uploading to S3: " + d); }
}

// GCP FAMILY
class GoogleComputeEngine implements ComputeInstance {
    public void bootUp()   { System.out.println("[GCP] Booting GCE..."); }
    public void shutDown() { System.out.println("[GCP] Stopping GCE."); }
}
class GoogleCloudStorage implements CloudStorage {
    public void uploadData(String d) { System.out.println("[GCP] Uploading to GCS: " + d); }
}

// ABSTRACT FACTORY
interface CloudInfrastructureFactory {
    ComputeInstance createComputeInstance();
    CloudStorage    createCloudStorage();
}

// CONCRETE FACTORIES
class AwsFactory implements CloudInfrastructureFactory {
    public ComputeInstance createComputeInstance() { return new EC2Instance(); }
    public CloudStorage    createCloudStorage()    { return new S3Storage(); }
}
class GcpFactory implements CloudInfrastructureFactory {
    public ComputeInstance createComputeInstance() { return new GoogleComputeEngine(); }
    public CloudStorage    createCloudStorage()    { return new GoogleCloudStorage(); }
}

// CLIENT
class DeploymentManager {
    private ComputeInstance compute;
    private CloudStorage    storage;

    public DeploymentManager(CloudInfrastructureFactory factory) {
        this.compute = factory.createComputeInstance();
        this.storage = factory.createCloudStorage();
    }
    public void deploy(String data) {
        compute.bootUp();
        storage.uploadData(data);
    }
}

// ABSTRACT PRODUCTS
interface TaxCalculator    { double calculateTax(double amount); }
interface PaymentProcessor { boolean processPayment(double total); }
interface ComplianceLogger { void logTransaction(String userId, double amount); }

// EU FAMILY
class VATCalculator implements TaxCalculator {
    public double calculateTax(double a) { return a * 0.20; }  // 20% VAT
}
class SEPAPaymentProcessor implements PaymentProcessor {
    public boolean processPayment(double a) { System.out.println("[EU] SEPA payment"); return true; }
}
class GDPRLogger implements ComplianceLogger {
    public void logTransaction(String id, double a) { System.out.println("[EU] GDPR anonymized log for " + id); }
}

// NA FAMILY
class StateSalesTax implements TaxCalculator {
    public double calculateTax(double a) { return a * 0.07; }  // 7% sales tax
}
class StripeProcessor implements PaymentProcessor {
    public boolean processPayment(double a) { System.out.println("[NA] Stripe USD payment"); return true; }
}
class SOXAuditor implements ComplianceLogger {
    public void logTransaction(String id, double a) { System.out.println("[NA] SOX plain-text log for " + id); }
}

// ABSTRACT FACTORY
interface IRegionalCheckoutFactory {
    TaxCalculator    createTaxCalculator();
    PaymentProcessor createPaymentProcessor();
    ComplianceLogger createComplianceLogger();
}

// CONCRETE FACTORIES
class EUCheckoutFactory implements IRegionalCheckoutFactory {
    public TaxCalculator    createTaxCalculator()    { return new VATCalculator(); }
    public PaymentProcessor createPaymentProcessor() { return new SEPAPaymentProcessor(); }
    public ComplianceLogger createComplianceLogger() { return new GDPRLogger(); }
}
class NACheckoutFactory implements IRegionalCheckoutFactory {
    public TaxCalculator    createTaxCalculator()    { return new StateSalesTax(); }
    public PaymentProcessor createPaymentProcessor() { return new StripeProcessor(); }
    public ComplianceLogger createComplianceLogger() { return new SOXAuditor(); }
}

// CLIENT
class CheckoutEngine {
    private TaxCalculator tax; private PaymentProcessor pay; private ComplianceLogger log;
    public CheckoutEngine(IRegionalCheckoutFactory f) {
        tax = f.createTaxCalculator(); pay = f.createPaymentProcessor(); log = f.createComplianceLogger();
    }
    public void checkout(String userId, double cart) {
        double total = cart + tax.calculateTax(cart);
        if (pay.processPayment(total)) log.logTransaction(userId, total);
    }
}

interface IShader  { void bind(); }
interface ITexture { void apply(); }

class DirectXShader  implements IShader  { public void bind()  { System.out.println("[DX] HLSL Shader"); } }
class DirectXTexture implements ITexture { public void apply() { System.out.println("[DX] DDS Texture"); } }
class VulkanShader   implements IShader  { public void bind()  { System.out.println("[VK] SPIR-V Shader"); } }
class VulkanTexture  implements ITexture { public void apply() { System.out.println("[VK] KTX Texture"); } }

interface IRendererFactory {
    IShader  compileShader();
    ITexture loadTexture();
}
class DirectXFactory implements IRendererFactory {
    public IShader compileShader() { return new DirectXShader(); }
    public ITexture loadTexture()  { return new DirectXTexture(); }
}
class VulkanFactory implements IRendererFactory {
    public IShader compileShader() { return new VulkanShader(); }
    public ITexture loadTexture()  { return new VulkanTexture(); }
}

class RenderPipeline {
    private IShader shader; private ITexture texture;
    public RenderPipeline(IRendererFactory f) {
        shader = f.compileShader(); texture = f.loadTexture();
    }
    public void drawFrame() { shader.bind(); texture.apply(); }
}

