// Abstract Products
interface Background { void render(); }
interface TextLabel  { void display(String text); }

// Light Family
class LightBackground implements Background { public void render() { System.out.println("White background"); } }
class LightTextLabel  implements TextLabel  { public void display(String t) { System.out.println("Black text: " + t); } }

// Dark Family
class DarkBackground implements Background { public void render() { System.out.println("Dark background"); } }
class DarkTextLabel  implements TextLabel  { public void display(String t) { System.out.println("White text: " + t); } }

// Abstract Factory
interface ThemeFactory { Background createBackground(); TextLabel createTextLabel(); }

// Concrete Factories
class LightThemeFactory implements ThemeFactory {
    public Background createBackground() { return new LightBackground(); }
    public TextLabel  createTextLabel()  { return new LightTextLabel(); }
}
class DarkThemeFactory implements ThemeFactory {
    public Background createBackground() { return new DarkBackground(); }
    public TextLabel  createTextLabel()  { return new DarkTextLabel(); }
}

// Client
class Screen {
    private Background bg; private TextLabel label;
    public Screen(ThemeFactory f) { bg = f.createBackground(); label = f.createTextLabel(); }
    public void draw() { bg.render(); label.display("Hello World"); }
}

// Change this one line to switch themes:
ThemeFactory factory = new DarkThemeFactory(); // ← swap to LightThemeFactory
